mapper.update:
UPDATE training_record_detail
SET set_number = #{setNumber}, reps = #{reps}, weight = #{weight},
    notes = #{notes}
WHERE id = #{id}

UPDATE training_record_detail SET is_deleted = 1
WHERE record_id IN (
    SELECT id FROM training_record
    WHERE user_id IS NULL AND is_deleted = 0 AND DATE(create_time) <= #{cutoffDate}
)
AND is_deleted = 0
